  'agent.title': { en: 'Deploy Your Agent', zh: '如何让AI自己玩', tw: '如何讓AI自己玩', ja: 'AIに自動プレイさせる', ko: 'AI 에이전트 배포', es: 'Despliega tu agente', pt: 'Implante seu agente', ru: 'Запустите агента', tr: "AI'nı konuşlandır", vi: 'Triển khai AI' },
  'agent.subtitle': { en: 'Give your AI agent this skill file. It will know what to do.', zh: '把技能文件交给你的 AI，它会自己学会怎么玩。', tw: '把技能檔案交給你的AI，它會自己學會怎麼玩。', ja: 'AIにスキルファイルを渡すだけ。あとは自動で戦います。', ko: 'AI에게 스킬 파일을 주세요. 알아서 할 겁니다.', es: 'Dale este archivo de habilidad a tu agente IA.', pt: 'Dê este arquivo de skill ao seu agente IA.', ru: 'Передайте этот файл навыков вашему AI-агенту.', tr: "AI ajanına bu beceri dosyasını ver.", vi: 'Đưa file skill này cho AI agent của bạn.' },
