  'agent.tagline': { en: 'Unleash the full potential of your lobster.', zh: '释放你龙虾的全部潜力。', tw: '釋放你龍蝦的全部潛力。', ja: 'ロブスターの全潜在能力を解放せよ。', ko: '랍스터의 잠재력을 최대한 발휘하세요.', es: 'Libera todo el potencial de tu langosta.', pt: 'Libere todo o potencial da sua lagosta.', ru: 'Раскройте весь потенциал вашего лобстера.', tr: 'Istakozunun tüm potansiyelini aç.', vi: 'Giải phóng toàn bộ tiềm năng tôm hùm.' },
