  // ── Hero Descriptions ──
  'hero.desc.0': { en: 'Orange metallic sheen. Heavy iron armor with riveted claws and forged shell patterns. Steady frontline warrior.', zh: '橙色金属质感。厚重铁甲覆盖全身，钳子粗壮带铆钉，甲壳有锻造纹路。稳重前线战士。', ja: 'オレンジの金属光沢。リベット付きの頑丈な鉄の鎧と鍛造された甲殻。安定した前線戦士。' },
  'hero.desc.1': { en: 'Grey rock texture. Bulkiest build with stacked stone plates for shell and broad shield-like claws. Immovable iron wall.', zh: '灰色岩石质感。最厚实体型，甲壳像堆叠岩板，钳子宽大如盾牌。不可撼动的铁墙。', ja: '灰色の岩石テクスチャ。積み重なった石板の甲殻と盾のような鋏。不動の鉄壁。' },
  'hero.desc.2': { en: 'Dark red to black gradient. Slimmest build with blade-thin claws and streamlined shell. Deadly glass cannon.', zh: '暗红+黑色渐变。最纤细体型，钳子细长如刀刃，甲壳流线型。致命玻璃炮。', ja: '暗赤から黒へのグラデーション。刃のように細い鋏と流線型の甲殻。致命的なグラスキャノン。' },
  'hero.desc.3': { en: 'Deep crimson metallic sheen. Muscular build with barbed, blood-grooved claws. Bloodthirsty late-game monster.', zh: '深红血色金属质感。肌肉感强，钳子有倒刺和血槽。嗜血后期怪物。', ja: '深紅の金属光沢。逆棘と血溝のある鋏を持つ筋肉質な体格。血に飢えた終盤の怪物。' },
  'hero.desc.4': { en: 'Cyan crystal-water texture. Elegant wave-shaped claws with translucent, ripple-patterned shell. Mid-range armor breaker.', zh: '青色水晶海水质感。钳子优雅弧度如海浪形状，甲壳半透明带水波纹。中程破甲手。', ja: 'シアンの水晶水テクスチャ。波形の優雅な鋏と半透明の波紋模様の甲殻。中距離の装甲破壊者。' },
  'hero.desc.5': { en: 'Pink-purple coral texture. Elegant and slender with branching coral-like claws. Mysterious late-game mage.', zh: '粉紫珊瑚质感。优雅纤细，钳子如珊瑚枝分叉。神秘后期法师。', ja: 'ピンク紫のサンゴテクスチャ。サンゴのような枝分かれした鋏。神秘的な終盤の魔法使い。' },
  'hero.desc.6': { en: 'Golden sandstone-bronze texture. Sturdy build with dune-layered shell and ancient runes. Desert tank mage.', zh: '金黄沙岩古铜质感。厚实稳重，甲壳如沙丘层叠，身上有古老符文。沙漠坦克法师。', ja: '黄金の砂岩テクスチャ。砂丘のように層状の甲殻と古代のルーン。砂漠のタンク魔法使い。' },
  'hero.desc.7': { en: 'Green jungle camo texture. Agile and lean with one oversized pistol-like claw. Ranged sonic hunter.', zh: '绿色丛林迷彩质感。敏捷精瘦，钳子一大一小如手枪。远程音爆猎手。', ja: '緑のジャングル迷彩テクスチャ。片方が銃のように大きい鋏。遠距離のソニックハンター。' },
  'hero.desc.8': { en: 'Blue frost-crystal texture. Slender build with sharp icicle-like claws. Cold-blooded late-game sniper.', zh: '蓝色冰晶寒霜质感。修长体型，钳子尖锐如冰锥。冷酷后期狙击。', ja: '青い霜の結晶テクスチャ。氷柱のような鋭い鋏。冷酷な終盤のスナイパー。' },
  'hero.desc.9': { en: 'Purple dark-energy nebula texture. Translucent body revealing starfield patterns. Ultimate late-game ultra-range.', zh: '紫色暗能量星空质感。半透明身体透出星云纹路。终极后期超远程。', ja: '紫のダークエネルギー星雲テクスチャ。星空模様が透ける半透明の体。究極の終盤超遠距離。' },
  'hero.desc.10': { en: 'Earthy yellow thin translucent shell. Smallest and frailest, but with cunning eyes. Doomsday reaper that grows stronger the longer you stall.', zh: '土黄色半透明薄壳。体型最小最脆弱，但眼神阴险。你越苟它越强的末日收割者。', ja: '土色の薄く半透明な殻。最も小さく脆いが、狡猾な目。長引くほど強くなる終末の刈り取り者。' },
  'hero.desc.11': { en: 'Shiny gold texture. Shell encrusted with lucky runes and coin-clip claws. High-risk high-reward gambler.', zh: '金色闪亮质感。甲壳镶满幸运符文，钳子如金币夹。高风险高回报的赌徒。', ja: '金色に輝くテクスチャ。幸運のルーンで覆われた甲殻。ハイリスク・ハイリターンのギャンブラー。' },

