export type MessageKey = keyof typeof messages;

// ── 全局语言状态 ──
let currentLang: Lang = (() => {
  if (typeof localStorage !== 'undefined') {
    const saved = localStorage.getItem('claw-arena-lang') as Lang | null;
    if (saved && LANGUAGES.some(l => l.code === saved)) return saved;
  }
  if (typeof navigator !== 'undefined') {
    const bl = navigator.language.toLowerCase();
    if (bl === 'zh-tw' || bl === 'zh-hk' || bl === 'zh-hant') return 'tw';
    if (bl.startsWith('zh')) return 'zh';
    if (bl.startsWith('ja')) return 'ja';
    if (bl.startsWith('ko')) return 'ko';
    if (bl.startsWith('es')) return 'es';
    if (bl.startsWith('pt')) return 'pt';
    if (bl.startsWith('ru')) return 'ru';
    if (bl.startsWith('tr')) return 'tr';
    if (bl.startsWith('vi')) return 'vi';
  }
  return 'en';
})();

const langListeners = new Set<() => void>();

export function getLang(): Lang { return currentLang; }

export function setLang(lang: Lang) {
  if (lang === currentLang) return;
  currentLang = lang;
  localStorage.setItem('claw-arena-lang', lang);
  langListeners.forEach(fn => fn());
}

export function subscribeLang(fn: () => void) {
  langListeners.add(fn);
  return () => { langListeners.delete(fn); };
}

export function useLang(): Lang {
  return useSyncExternalStore(subscribeLang, getLang);
}

export function t(key: MessageKey | string, fallback?: string): string {
  const entry = messages[key as MessageKey];
  if (!entry) return fallback ?? key;
  return entry[currentLang] || entry.en;
}

export default messages;
